const r=(a="light")=>{if("vibrate"in navigator)switch(a){case"light":navigator.vibrate(10);break;case"medium":navigator.vibrate(20);break;case"success":navigator.vibrate([10,30,10]);break;case"warning":navigator.vibrate([30,50,30]);break;case"error":navigator.vibrate([50,100,50,100,50]);break;default:navigator.vibrate(10)}};export{r as t};
